import React, {useState} from "react";
//import CuteParameterCard from "../components/CuteParameterCard/CuteParameterCard";
// import CuteParameterCard from "../components/DataEntity/NewCuteParameterCard2";
import DynamicParameterCard from "../components/DataEntity/DynamicParameterCard";


function Testpage() {
    const [params, setParams] = useState({});
    const data = {
        "theme": "pink",
        "components": [

            {
                "id": "mood",
                "type": "double-click-selector",
                "name": "心情状态",
                "defaultValue": null,
                "icon": "Star",
                "colorIndex": 5
            },
            {
                "id": "brightness",
                "type": "slider",
                "name": "亮度",
                "defaultValue": 75,
                "min": 0,
                "max": 200,
                "icon": "Sun",
                "colorIndex": 3
            },
            {
                "id": "volume",
                "type": "slider",
                "name": "音量",
                "defaultValue": 60,
                "min": 0,
                "max": 50,
                "icon": "Volume2",
                "colorIndex": 1
            },
            {
                "id": "speed",
                "type": "selector",
                "name": "速度",
                "defaultValue": 3,
                "icon": "Zap",
                "colorIndex": 2
            },
            {
                "id": "hearts",
                "type": "counter",
                "name": "爱心数量",
                "defaultValue": 5,
                "min": 0,
                "max": 10,
                "icon": "Heart",
                "colorIndex": 6
            },
            {
                "id": "sparkle",
                "type": "switch",
                "name": "闪闪特效",
                "defaultValue": true,
                "icon": "Sparkles",
                "colorIndex": 5
            },
            {
                "id": "theme",
                "type": "theme-selector",
                "name": "主题色彩",
                "defaultValue": "pink",
                "icon": "Moon",
                "colorIndex": 9
            },
            // {
            //     "id": "energy",
            //     "type": "number-input",
            //     "name": "能量值",
            //     "defaultValue": 80,
            //     "min": 0,
            //     "max": 100,
            //     "icon": "Zap",
            //     "colorIndex": 7
            // }
        ]
    }
    return (
        <div>
            <DynamicParameterCard
                RenderConfig={data}
                params={params}
                setParams={setParams}
            />
        </div>
    )
}

export default Testpage
